// Series grouping for sidebar and dashboard
// To add a new series: push a new { label, ids[] } object
// Flag helper: returns <img> for the set's language
function setFlagHtml(set) {
  var codes = { KR: 'kr', JP: 'jp', CN: 'cn' };
  var code = codes[set.lang] || 'kr';
  return '<img src="https://flagcdn.com/w20/' + code + '.png" ' +
         'style="width:14px;height:10px;object-fit:cover;border-radius:2px;vertical-align:middle;flex-shrink:0;" ' +
         'alt="' + (set.lang || 'KR') + '">';
}


